import { Mail, Linkedin, Github, Phone } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const links = [
  { href:'mailto:karemalwy1@gmail.com', label:'karemalwy1@gmail.com', icon:<Mail size={14}/> },
  { href:'https://www.linkedin.com/in/karem-basem', label:'LinkedIn', icon:<Linkedin size={14}/> },
  { href:'https://github.com/Kareem-Basem', label:'GitHub', icon:<Github size={14}/> },
  { href:'tel:+201062294558', label:'+20 106 229 4558', icon:<Phone size={14}/> },
];

export default function Contact() {
  const { lang } = useApp();
  const tr = t[lang];

  return (
    <>
      <section id="contact" className="py-28 px-[5%] bg-ink relative overflow-hidden">
        <div className="blob-hero w-[460px] h-[460px] bg-amber opacity-[.05] -top-24 -right-20 pointer-events-none" />
        <div className="relative z-10 max-w-2xl">
          <p className="text-xs font-semibold tracking-[.14em] uppercase text-amber mb-3">{tr.conTag}</p>
          <h2 className="font-serif-display text-5xl md:text-7xl tracking-tight leading-[.95] text-white mb-5"
            dangerouslySetInnerHTML={{ __html: tr.conTitle.replace('<em>', '<em class="italic text-amber font-serif-display">') }} />
          <p className="text-[.96rem] text-white/40 leading-[1.8] mb-8 max-w-[460px]">{tr.conSub}</p>
          <div className="flex flex-wrap gap-2.5">
            {links.map(l => (
              <a key={l.label} href={l.href} target={l.href.startsWith('http')?'_blank':undefined} rel="noreferrer"
                className="flex items-center gap-2 px-4 py-2.5 rounded-full border-[1.5px] border-white/10 text-white/60 text-sm font-medium transition-all hover:border-amber hover:text-amber hover:-translate-y-0.5">
                {l.icon}{l.label}
              </a>
            ))}
          </div>
        </div>
      </section>
      <footer className="bg-[#111124] px-[5%] py-5 flex flex-col md:flex-row justify-between items-center gap-2 text-[.72rem] text-white/25">
        <span>© 2026 Kareem Basem Fathi</span>
        <span>MIS · Sadat Academy · Asyut, Egypt</span>
      </footer>
    </>
  );
}
